// Import required libraries
const Web3 = require('web3');
const fs = require('fs');

// Set up Web3 provider (for example, use Infura.io)
const web3Provider = new Web3.providers.HttpProvider('https://mainnet.infura.io/v3/YOUR_PROJECT_ID');

// Set up the Web3 instance
const web3 = new Web3(web3Provider);

// Load wallet configuration from file
const privateKeyFile = 'path/to/private/key.json';
const walletConfig = JSON.parse(fs.readFileSync(privateKeyFile, 'utf8'));

// Function to send ETH transaction
async function sendEth(amount) {
  const txParams = {
    from: walletConfig.address,
    to: 'recipient-address',
    value: web3.utils.toWei(amount.toString(), 'ether'),
    gas: '20000',
    gasPrice: web3.utils.toWei('20', 'gwei')
  };

  try {
    const txHash = await web3.eth.sendTransaction(txParams);
    console.log(`ETH transaction sent with hash ${txHash}`);
  } catch (error) {
    console.error('Error sending ETH transaction:', error);
  }
}

// Function to interact with smart contract
async function interactWithContract(contractAddress, contractAbi, functionName, ...args) {
  try {
    const contract = new web3.eth.Contract(contractAbi, contractAddress);
    const txCount = await web3.eth.getTransactionCount(walletConfig.address);

    const txParams = {
      from: walletConfig.address,
      to: contract.options.address,
      gas: '20000',
      gasPrice: web3.utils.toWei('20', 'gwei'),
      nonce: txCount
    };

    const rawTransaction = await contract.methods[functionName](...args).encodeABI();
    txParams.data = rawTransaction;

    const signedTx = await web3.eth.accounts.signTransaction(txParams, walletConfig.privateKey);
    const receipt = await web3.eth.sendSignedTransaction(signedTx.rawTransaction);

    console.log(`Contract interaction successful with hash ${receipt.transactionHash}`);
  } catch (error) {
    console.error('Error interacting with contract:', error);
  }
}

// Example usage:
async function main() {
  // Send ETH transaction
  await sendEth(1.0);

  // Interact with smart contract
  const contractAbi = require('./path/to/contract/abi.json');
  await interactWithContract('smart-contract-address', contractAbi, 'methodName', arg1, arg2);
}

main().catch((error) => {
  console.error(error);
});